# test_topological_sort.py
import pytest

from your_module import topological_sort  # replace with the actual module name


def assert_valid_topological_order(graph, order):
    """
    Assert that `order` is a valid topological ordering for `graph`.

    For every edge u -> v, u must appear before v.
    Also verifies that all nodes, including neighbor-only nodes, are present once.
    """
    expected_nodes = set(graph.keys())
    for neighbors in graph.values():
        expected_nodes.update(neighbors)

    assert set(order) == expected_nodes
    assert len(order) == len(expected_nodes)

    position = {node: index for index, node in enumerate(order)}

    for node, neighbors in graph.items():
        for neighbor in neighbors:
            assert position[node] < position[neighbor]


def test_empty_graph_returns_empty_list():
    assert topological_sort({}) == []


def test_single_node_graph():
    graph = {"a": []}

    result = topological_sort(graph)

    assert result == ["a"]


def test_simple_linear_graph():
    graph = {
        "a": ["b"],
        "b": ["c"],
        "c": [],
    }

    result = topological_sort(graph)

    assert_valid_topological_order(graph, result)


