def test_cycle_does_not_raise_but_result_is_not_valid_topological_order():
    """
    The current implementation does not detect cycles.

    This test documents the current behavior: it terminates and returns nodes,
    but the result cannot be a valid topological ordering.
    """
    graph = {
        "a": ["b"],
        "b": ["a"],
    }

    result = topological_sort(graph)

    assert set(result) == {"a", "b"}
    assert len(result) == 2

    position = {node: index for index, node in enumerate(result)}
    assert not all(
        position[node] < position[neighbor]
        for node, neighbors in graph.items()
        for neighbor in neighbors
    )


